using Microsoft.UI.Xaml; using Microsoft.UI.Xaml.Controls;
namespace FlyPPTTimer.WinUI.Pages;
public sealed partial class HotkeysPage:Page{public HotkeysPage(){InitializeComponent();var h=App.Services.Controller.Config.Controls.Hotkeys;StartPause.Text=h.GetValueOrDefault("startPause");StopReset.Text=h.GetValueOrDefault("stopReset");ToggleWindow.Text=h.GetValueOrDefault("toggleWindow");OpenSettings.Text=h.GetValueOrDefault("openSettings");Flash.Text=h.GetValueOrDefault("flash");Mute.Text=h.GetValueOrDefault("toggleMute");}private void Apply_Click(object s,RoutedEventArgs e){var c=App.Services.Controller.CreateEditableConfig();c.Controls.Hotkeys["startPause"]=StartPause.Text.Trim();c.Controls.Hotkeys["stopReset"]=StopReset.Text.Trim();c.Controls.Hotkeys["toggleWindow"]=ToggleWindow.Text.Trim();c.Controls.Hotkeys["openSettings"]=OpenSettings.Text.Trim();c.Controls.Hotkeys["flash"]=Flash.Text.Trim();c.Controls.Hotkeys["toggleMute"]=Mute.Text.Trim();App.Services.ViewModel.ApplyConfig(c);}}
